def string_xor(a: str, b: str) -> str:
    """ Input are two strings a and b consisting only of 1s and 0s.
    Perform binary XOR on these inputs and return result also as a string.
    >>> string_xor('010', '110')
    '100'
    """
    if len(a)!= len(b):
        raise ValueError('Input strings must be of equal length')
    result = []
    for i in range(len(a)):
        # convert each bit of the strings to an int (0 or 1)
        # xor the ints, convert the result back to a bit string
        # (0 or 1) then add to result string
        bit1, bit2 = int(a[i]), int(b[i])
        xor_bit = '{0:b}'.format(bit1 ^ bit2)
        # pad with leading 0 if needed (e.g. 0^1=1)
        xor_bit = xor_bit.zfill(2)
        result.append(xor_bit)
    result = ''.join(result)
    return result

